let _allRaces=[];async function initRacesPage(){await loadRaces(SeasonState.get()),initFilters(),window.addEventListener("seasonChanged",({detail:e})=>loadRaces(e.year))}async function loadRaces(e){const t=document.getElementById("races-grid");showLoading(t);try{if(_allRaces=await Races.list(e),!_allRaces?.length)return void showEmpty(t,"Гонки не найдены","Данные ещё не загружены","🏁");populateCountryFilter(),renderRaces(_allRaces)}catch(e){showError(t,e.message)}}function renderRaces(e){const t=document.getElementById("races-grid"),a=new Date,n=[...e].sort((e,t)=>new Date(e.race_date)-new Date(t.race_date));n.length?t.innerHTML=n.map(e=>{const t="upcoming"===e.status&&new Date(e.race_date)>a,r=n.find(e=>"upcoming"===e.status&&new Date(e.race_date)>a)?.id===e.id,c=e.banner_url?`<img src="${escapeHtml(e.banner_url)}" class="race-card-banner" alt="${escapeHtml(e.name)}" loading="lazy" onerror="this.style.display='none'">`:'<div class="race-card-banner-placeholder">🏎</div>';return`\n      <div class="race-card ${r?"upcoming":""}" onclick="window.location='/race-detail.html?id=${e.id}'">\n        ${c}\n        <div class="race-card-body">\n          <div class="race-round">Этап ${e.round} · ${e.country||""}</div>\n          <h3 class="race-name">${escapeHtml(e.name)}</h3>\n          <div class="race-meta">\n            <span>📍 ${escapeHtml(e.city||"")}${e.city&&e.circuit_name?" · ":""}${escapeHtml(e.circuit_name||"")}</span>\n          </div>\n          <div class="race-card-footer">\n            <div>\n              ${getRaceStatusBadge(e.status)}\n              ${r?'<span class="badge badge-teal" style="margin-left:6px;">Следующая</span>':""}\n            </div>\n            <div style="text-align:right;">\n              <div style="font-family:var(--font-display);font-weight:700;color:${t?"var(--teal)":"var(--text-primary)"};">${formatDateShort(e.race_date)}</div>\n              ${e.race_date?`<div style="font-size:.73rem;color:var(--text-muted);">${formatTime(e.race_date)}</div>`:""}\n            </div>\n          </div>\n          ${e.winner?`<div class="race-winner" style="margin-top:10px;padding-top:10px;border-top:1px solid var(--border);">🏆 <strong>${escapeHtml(e.winner)}</strong></div>`:""}\n        </div>\n      </div>\n    `}).join(""):showEmpty(t,"Гонки не найдены")}function populateCountryFilter(){const e=document.getElementById("filter-country");if(!e)return;const t=[...new Set(_allRaces.map(e=>e.country).filter(Boolean))].sort();e.innerHTML='<option value="">Все страны</option>'+t.map(e=>`<option value="${escapeHtml(e)}">${escapeHtml(e)}</option>`).join("")}function applyFilters(){const e=document.getElementById("search-race")?.value.toLowerCase()||"",t=document.getElementById("filter-country")?.value||"",a=document.getElementById("filter-status")?.value||"";renderRaces(_allRaces.filter(n=>!(e&&!n.name?.toLowerCase().includes(e))&&((!t||n.country===t)&&(!a||n.status===a))))}function initFilters(){["search-race","filter-country","filter-status"].forEach(e=>{document.getElementById(e)?.addEventListener("input",applyFilters),document.getElementById(e)?.addEventListener("change",applyFilters)})}document.addEventListener("DOMContentLoaded",initRacesPage);